@namespace Lumeo

@{
    var context = new DrawerContext(Open, EventCallback.Factory.Create<bool>(this, SetOpen), _titleId, _descriptionId, TryDismiss, _descriptionRegistry, RegisterDescription, UnregisterDescription);
}

<CascadingValue Value="context" IsFixed="false">
    @ChildContent
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    /// <summary>
    /// Fires before any user-initiated dismiss (Escape, backdrop click,
    /// swipe gesture, or a <c>DrawerClose</c> trigger). Set
    /// <see cref="DismissEventArgs.Cancel"/> to <c>true</c> to abort. The
    /// <see cref="DismissEventArgs.Reason"/> tells you which path fired
    /// (<c>"escape"</c>, <c>"outside"</c>, <c>"swipe"</c>, <c>"close"</c>).
    /// </summary>
    [Parameter] public EventCallback<DismissEventArgs> OnBeforeClose { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    private readonly string _titleId = LumeoIds.New("drawer-title");
    private readonly string _descriptionId = LumeoIds.New("drawer-desc");

    // Tracks whether a <DrawerDescription> is actually present in the tree. A
    // mutable holder (not a record field) because the cascaded context is
    // rebuilt every render, but the registration must persist across renders.
    // Mirrors AlertDialog's DescriptionRegistry — without this DrawerContent
    // would emit a dangling aria-describedby IDREF whenever no description is
    // rendered (e.g. every service-opened overlay).
    private readonly DrawerDescriptionRegistry _descriptionRegistry = new();

    private async Task SetOpen(bool value)
    {
        Open = value;
        await OpenChanged.InvokeAsync(value);
    }

    private async Task<bool> TryDismiss(string reason)
    {
        if (OnBeforeClose.HasDelegate)
        {
            var args = new DismissEventArgs { Reason = reason };
            await OnBeforeClose.InvokeAsync(args);
            if (args.Cancel) return false;
        }
        await SetOpen(false);
        return true;
    }

    // Called by DrawerDescription on init so DrawerContent only wires
    // aria-describedby when a description actually exists (no dangling IDREF).
    // Re-renders so the content's aria-describedby picks up the registration on
    // the next pass (child OnInitialized runs after the parent's first render).
    // Counted (not a bool) so a description that is conditionally REMOVED while
    // the drawer stays mounted is correctly un-registered via UnregisterDescription
    // below (Codex P2) — a bare bool latched true forever.
    private void RegisterDescription()
    {
        _descriptionRegistry.Count++;
        if (_descriptionRegistry.Count == 1) StateHasChanged();
    }

    // Called by DrawerDescription.Dispose when it is removed from the tree.
    // Only re-renders on the 1->0 transition.
    private void UnregisterDescription()
    {
        _descriptionRegistry.Count--;
        if (_descriptionRegistry.Count == 0) StateHasChanged();
    }

    // DescriptionRegistry + RegisterDescription/UnregisterDescription default to null! so the 4.0
    // additions stay a non-breaking signature change: Lumeo always constructs the context with real
    // values, and any external 3.x constructor of the 5-arg shape still compiles.
    public record DrawerContext(bool IsOpen, EventCallback<bool> SetOpen, string TitleId, string DescriptionId, Func<string, Task<bool>> TryDismiss, DrawerDescriptionRegistry DescriptionRegistry = null!, Action RegisterDescription = null!, Action UnregisterDescription = null!);

    /// <summary>
    /// Persistent, mutable holder that survives the per-render rebuild of
    /// <see cref="DrawerContext"/>. Lets <see cref="DrawerContent"/> know whether
    /// a <see cref="DrawerDescription"/> is CURRENTLY rendered so it can avoid
    /// emitting a dangling <c>aria-describedby</c> IDREF (mirrors the AlertDialog
    /// pattern). A count, not a bool, so a description that mounts then is later
    /// removed un-registers.
    /// </summary>
    public sealed class DrawerDescriptionRegistry
    {
        public int Count { get; set; }
        public bool HasDescription => Count > 0;
    }
}

@namespace Lumeo

<div class="@CssClass" role="button" tabindex="0" @onclick="Close" @onkeydown="HandleKeyDown" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public Drawer.DrawerContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string CssClass => Cx.Merge("inline-flex", Class);

    // Route through TryDismiss so OnBeforeClose handlers can guard the
    // close from a custom button just like the built-in Escape / swipe paths.
    private async Task Close() => await Context.TryDismiss("close");

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key is "Enter" or " ") await Close();
    }
}

@namespace Lumeo
@using Lumeo.Services
@implements IAsyncDisposable
@implements IOverlayExitCallback

@*
    Animation=Slide is now safe (rc.21 fixed the transform trap), but
    Animation=Fade or None still available for consumers who want maximum
    predictability. The Slide keyframes were updated so they end at
    `transform: none` rather than an identity-translate, which used to create
    a CSS containing-block trap that broke `position: fixed` popovers
    (Select/DatePicker/Combobox) rendered inside a Drawer.
*@

@if (Shell is not null)
{
    @* See OverlayShellMarker — host DrawerContent already painted the shell.
       Pass children through to avoid a second backdrop + panel + swipe handler. *@
    @ChildContent
}
else if (Context.IsOpen || _exiting)
{
    @* pointer-events-none wrapper + -auto on backdrop/panel: the full-viewport
       wrapper must never be a hit-target itself. A drawer panel that wedges
       mid slide-in (mobile viewport shift) previously left this invisible layer
       swallowing every tap below it — the reported "second drawer breaks and the
       first can no longer be closed" failure shape (B4 hardening). *@
    <div class="fixed inset-0 pointer-events-none" style="z-index:@BackdropZ">
        @* Backdrop — theme-aware --color-overlay-backdrop token (was a hardcoded
           bg-black/80 that ignored the token, unlike Sheet/Dialog). #218. Fades
           out alongside the panel while exiting (service-opened only). *@
        <div class="@BackdropClass" style="@BackdropStyle" @onclick="HandleBackdropClick"></div>
        @* @onkeydown:stopPropagation — keys handled inside this modal must not
           bubble into ancestor overlays (an Escape would cascade-close them).
           See DialogContent for the full rationale. aria-modal drops to false
           while exiting (affordances already torn down — mirrors SheetContent #185). *@
        <div id="@_contentId" class="@CssClass" style="z-index:@ContentZ" role="dialog" aria-modal="@(Context.IsOpen ? "true" : "false")" aria-labelledby="@Context.TitleId" aria-describedby="@DescribedBy" @onkeydown="HandleKeyDown" @onkeydown:stopPropagation tabindex="-1" inert="@ExitInert" @attributes="AdditionalAttributes">
            @if (ShowDragHandle)
            {
                <div class="mx-auto mt-4 h-2 w-[100px] rounded-full bg-muted"></div>
            }
            @ChildContent
        </div>
    </div>
}

@inject IComponentInteropService Interop
@inject Microsoft.Extensions.Options.IOptions<Lumeo.Services.LumeoGestureOptions> GestureOpts
@inject Lumeo.Services.ThemeService Theme

@code {
    [CascadingParameter] public Drawer.DrawerContext Context { get; set; } = default!;
    [CascadingParameter] public OverlayShellMarker? Shell { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public Lumeo.Side Side { get; set; } = Lumeo.Side.Bottom;
    [Parameter] public DrawerAnimation Animation { get; set; } = DrawerAnimation.Slide;
    [Parameter] public bool PreventClose { get; set; }

    /// <summary>
    /// vaul-style snap points: fractional resting heights in ascending order,
    /// each <c>0 &lt; f ≤ 1</c> (e.g. <c>[0.4, 0.75, 1]</c> = 40% / 75% / fully
    /// open). When set on a Top/Bottom drawer, the panel rests at one of these
    /// heights, drags between them, and dismisses when flicked/dragged below the
    /// lowest. Ignored for Left/Right (which keep plain swipe-to-dismiss). (#218)
    /// </summary>
    [Parameter] public IReadOnlyList<double>? SnapPoints { get; set; }

    /// <summary>
    /// Index into <see cref="SnapPoints"/> of the current resting snap. Two-way
    /// bindable: updates as the user drags between snaps, and setting it moves
    /// the drawer programmatically. <c>-1</c> (default) opens at the most-open
    /// (last) snap. (#218)
    /// </summary>
    [Parameter] public int ActiveSnapPoint { get; set; } = -1;
    [Parameter] public EventCallback<int> ActiveSnapPointChanged { get; set; }

    [Parameter] public string? Class { get; set; }
    /// <summary>When <c>true</c> (the default), closing keeps the panel mounted for
    /// a slide/fade out before unmounting instead of vanishing instantly — so a
    /// declarative drawer animates its close the same way <see cref="OverlayProvider"/>
    /// already animates service-opened ones. Set to <c>false</c> to opt OUT
    /// (immediate unmount) for tests or consumers who want an instant dismiss.
    /// Ignored in snap-point mode (the JS gesture owns the transform).</summary>
    [Parameter] public bool PlayExitAnimation { get; set; } = true;
    /// <summary>Backdrop z-index. Content sits at <c>ZIndex + 1</c>. Defaults
    /// to <see cref="OverlayService.BaseZIndex"/>; <see cref="OverlayProvider"/>
    /// supplies an incrementing value per nested overlay.</summary>
    [Parameter] public int ZIndex { get; set; } = OverlayService.BaseZIndex;
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _contentId = LumeoIds.New("drawer");
    // True once we've rendered open and not yet processed the close. Drives the
    // exit animation INDEPENDENTLY of whether the open-interop finished — a dismiss
    // during the Blazor Server interop round-trip window still slides out instead of
    // vanishing (the B11 "no exit animation on real apps" regression). See
    // SheetContent for the full write-up.
    private bool _shownOpen;
    // True once the open-interop chain (scroll lock + focus trap + slide-end +
    // gesture) has run and needs tearing down on close. On Server the panel is
    // visible and dismissable before this flips true.
    private bool _interopReady;
    // Exit-animation state — see DialogContent / SheetContent. Only set when
    // PlayExitAnimation is true (service-opened drawers) and not in snap mode.
    private bool _exiting;
    private readonly DelayedDispatch _exitDispatch = new();
    // Radix-Presence parity: the real unmount is driven by the panel's own
    // animationend (attachOverlayExitEnd), which also clears the open-time inline
    // animation:none guard so the slide-out can run. _exitDispatch is the fallback.
    private DotNetObjectReference<DrawerContent>? _selfRef;
    private bool _exitWired;

    // FALLBACK window only — the real unmount is the panel's animationend
    // (OnExitAnimationEnd). Sits above the CSS duration (slide 300ms, fade 150ms)
    // so the timer never preempts a slightly-late animationend; it covers only the
    // JS-dead / lost-event case. 0 when no exit animation applies (exit opted out
    // via PlayExitAnimation=false, snap mode, or Animation=None) → immediate unmount.
    private int ExitDurationMs => (PlayExitAnimation && !UsesSnapPoints)
        ? (Animation switch { DrawerAnimation.Slide => 450, DrawerAnimation.Fade => 260, _ => 0 })
        : 0;

    // The exiting backdrop KEEPS pointer-events-auto so it goes on shielding the
    // page beneath until it unmounts — a modal backdrop must block the page until
    // it is gone (Radix keeps the overlay blocking until close completes), so a
    // fast double-click during the fade lands on the scrim, not on the page below.
    // HandleBackdropClick is already a no-op while exiting (it gates on
    // Context.IsOpen), so swallowing that click can't re-trigger a dismiss/reopen.
    // The PANEL stays pointer-events-none + inert (PointerClass / ExitInert).
    private string BackdropClass => _exiting
        ? "fixed inset-0 animate-fade-out pointer-events-auto"
        : "fixed inset-0 animate-fade-in pointer-events-auto";

    // Exit-window inertness (mirrors DropdownMenuContent). While the panel is kept
    // mounted for the slide/fade-out (Context.IsOpen == false, _exiting == true) its
    // focus trap + scroll lock + gesture are already torn down, so make the leaving
    // panel pointer-events-none + inert: no stray tap / Tab hits a closing drawer.
    // Focus was restored to the trigger by RemoveFocusTrap at close time, independent
    // of this. _exiting is never set in snap mode (ExitDurationMs == 0), so a snap-mode
    // dismiss keeps pointer-events-auto and unmounts immediately — unaffected.
    private string PointerClass => _exiting ? "pointer-events-none" : "pointer-events-auto";
    private string? ExitInert => _exiting ? "true" : null;

    // Couple the backdrop exit duration to the panel's slide duration (300ms)
    // when the Slide animation is active — identical rationale to SheetContent.
    // Snap mode is excluded (the JS gesture owns the panel transform; no CSS
    // slide-out plays, so the backdrop uses its default 0.15s fade-out).
    private string BackdropStyle => (_exiting && Animation == DrawerAnimation.Slide && !UsesSnapPoints)
        ? $"background-color:var(--color-overlay-backdrop);z-index:{BackdropZ};animation-duration:300ms"
        : $"background-color:var(--color-overlay-backdrop);z-index:{BackdropZ}";

    // Slide-animation transform trap is fixed via JS interop:
    // Interop.AttachOverlaySlideEnd registers a native animationend listener
    // that filters strictly on slide-in-from-* AND on event.target === this
    // element, then sets inline `transform: none`. See SheetContent for the
    // full rationale.

    private int BackdropZ => ZIndex;
    private int ContentZ => ZIndex + 1;

    // Only reference the description id when a <DrawerDescription> was actually
    // rendered; otherwise aria-describedby would dangle to a missing element
    // (returning null makes Blazor omit the attribute entirely). This is what
    // every service-opened Drawer (no description child) hits.
    private string? DescribedBy => Context.DescriptionRegistry.HasDescription ? Context.DescriptionId : null;

    private bool ShowDragHandle => Side is Lumeo.Side.Top or Lumeo.Side.Bottom;

    // Snap points only apply to vertical drawers (vaul is vertical-only).
    private bool UsesSnapPoints => SnapPoints is { Count: > 0 } && Side is Lumeo.Side.Top or Lumeo.Side.Bottom;

    // Clamp the requested initial snap into range; -1 (default) → most-open (last).
    private int InitialSnapIndex
    {
        get
        {
            var last = (SnapPoints?.Count ?? 1) - 1;
            return (ActiveSnapPoint >= 0 && ActiveSnapPoint <= last) ? ActiveSnapPoint : last;
        }
    }

    // Last index we pushed to / received from JS, to distinguish a consumer's
    // programmatic ActiveSnapPoint change from an echo of a gesture-driven one.
    private int _appliedSnap = -1;

    // Which gesture path was actually registered on open, so cleanup and
    // programmatic updates target the right one even if SnapPoints/Side change
    // while the drawer stays open (PR #345 review).
    private bool _gestureRegistered;
    private bool _registeredWithSnap;

    // The swipe direction + snap-point geometry baked into the live JS gesture.
    // A runtime Side/RTL flip (#76) or a same-count SnapPoints fraction change
    // (#77) doesn't trip the mode-flip gate below, so the gesture would keep the
    // OLD edge / resting offsets. We record what was actually registered and
    // re-register when it diverges. Seeded inside RegisterGestureAsync.
    private string? _registeredDirection;
    private double[]? _registeredSnapPoints;

    private string PositionClasses => Side switch
    {
        Lumeo.Side.Top => "inset-x-0 top-0 rounded-b-[10px] max-h-[96vh]",
        Lumeo.Side.Right => "inset-y-0 end-0 w-3/4 max-w-sm rounded-s-[10px] h-full max-h-screen",
        Lumeo.Side.Bottom => "inset-x-0 bottom-0 rounded-t-[10px] max-h-[96vh]",
        Lumeo.Side.Left => "inset-y-0 start-0 w-3/4 max-w-sm rounded-e-[10px] h-full max-h-screen",
        _ => "inset-x-0 bottom-0 rounded-t-[10px] max-h-[96vh]"
    };

    // Snap mode: the JS gesture owns the transform (slide-in + resting offset),
    // so the CSS slide keyframe is suppressed to avoid fighting it. While exiting
    // (service-opened close) the panel slides/fades back out toward its edge.
    private string AnimationClass => UsesSnapPoints ? "" : (_exiting ? ExitAnimationClass : EnterAnimationClass);

    private string EnterAnimationClass => Animation switch
    {
        DrawerAnimation.None => "",
        DrawerAnimation.Fade => "animate-fade-in",
        DrawerAnimation.Slide => Side switch
        {
            Lumeo.Side.Top => "animate-slide-in-from-top",
            Lumeo.Side.Right => "animate-slide-in-from-right",
            Lumeo.Side.Bottom => "animate-slide-in-from-bottom",
            Lumeo.Side.Left => "animate-slide-in-from-left",
            _ => "animate-slide-in-from-bottom"
        },
        _ => ""
    };

    private string ExitAnimationClass => Animation switch
    {
        DrawerAnimation.None => "",
        DrawerAnimation.Fade => "animate-fade-out",
        DrawerAnimation.Slide => Side switch
        {
            Lumeo.Side.Top => "animate-slide-out-to-top",
            Lumeo.Side.Right => "animate-slide-out-to-right",
            Lumeo.Side.Bottom => "animate-slide-out-to-bottom",
            Lumeo.Side.Left => "animate-slide-out-to-left",
            _ => "animate-slide-out-to-bottom"
        },
        _ => ""
    };

    private string CssClass =>
        Cx.Merge("fixed mt-24 flex h-auto flex-col bg-background shadow-lg", PositionClasses, AnimationClass, PointerClass, Class);

    // A scoped <DirectionProvider> wins over the global ThemeService, so a subtree
    // can be RTL even if the app is LTR. Null when no provider wraps this drawer.
    [CascadingParameter(Name = "LumeoDirection")] private LayoutDirection? ScopedDirection { get; set; }
    private LayoutDirection EffectiveDirection => ScopedDirection ?? Theme.CurrentDirection;

    // PositionClasses use logical start/end-0 and the slide keyframes mirror under
    // [dir=rtl], so under RTL a Side.Right drawer rests on (and animates from) the
    // visual LEFT edge. The swipe direction must follow that visual edge — otherwise
    // a right-side RTL drawer only dismisses by dragging toward the page instead of
    // off its anchored edge. Top/Bottom are unaffected by direction.
    private Lumeo.Side EffectiveSide => EffectiveDirection == LayoutDirection.Rtl
        ? Side switch
        {
            Lumeo.Side.Left => Lumeo.Side.Right,
            Lumeo.Side.Right => Lumeo.Side.Left,
            var s => s,
        }
        : Side;

    private string SwipeDirection => EffectiveSide switch
    {
        Lumeo.Side.Top => "up",
        Lumeo.Side.Right => "right",
        Lumeo.Side.Bottom => "down",
        Lumeo.Side.Left => "left",
        _ => "down"
    };

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        // Passthrough mode — host DrawerContent owns scroll lock, focus trap, swipe.
        if (Shell is not null) return;

        if (Context.IsOpen && !_interopReady)
        {
            // Mark BEFORE the awaits so a dismiss Server-dispatched between the
            // interop round-trips hits the undo-check below exactly once.
            _interopReady = true;
            try
            {
                await Interop.LockScroll();
                await Interop.SetupFocusTrap(_contentId);
                // Same animationend cleanup as SheetContent — bypasses Blazor
                // event roundtrip + filters strictly on slide-in-from-* names.
                // Skipped in snap mode: the JS snap gesture owns the transform.
                if (!UsesSnapPoints && Animation == DrawerAnimation.Slide)
                {
                    await Interop.AttachOverlaySlideEnd(_contentId);
                }
                await RegisterGestureAsync();
            }
            catch (JSDisconnectedException) { }

            // Dismissed while the open interop was still in flight (the Server
            // round-trip window that used to swallow the slide-out): tear the
            // just-registered handlers back down. The slide-out itself is owned by
            // OnParametersSetAsync, so it plays regardless.
            if (!Context.IsOpen)
            {
                await Cleanup();
                _interopReady = false;
            }
        }
        else if (!Context.IsOpen && _interopReady)
        {
            // Close: tear down scroll-lock / focus-trap / gesture (focus returns to
            // the trigger now). The slide-out + deferred unmount are already
            // scheduled by OnParametersSetAsync — this branch is interop teardown
            // only.
            await Cleanup();
            _interopReady = false;
        }

        // Radix-Presence parity: hand the unmount to the panel's OWN exit
        // animationend. attachOverlayExitEnd first strips the open-time inline
        // animation:none/transform:none guard (otherwise it overrides the
        // animate-slide-out-* class and the panel can't move — the B11 root cause),
        // then notifies OnExitAnimationEnd once the slide/fade-out finishes so the
        // backdrop + panel drop together. _exitDispatch stays armed as a fallback.
        if (_exiting && !_exitWired)
        {
            _exitWired = true;
            _selfRef ??= DotNetObjectReference.Create(this);
            try { await Interop.AttachOverlayExitEnd(_contentId, _selfRef); }
            catch (JSDisconnectedException) { }
        }
    }

    // Invoked from JS (attachOverlayExitEnd) when the panel's exit animation ends.
    [JSInvokable]
    public Task OnExitAnimationEnd() => InvokeAsync(FinishExit);

    // Ends the exit phase: cancel the fallback timer and drop backdrop + panel in
    // the same render commit. Idempotent with the fallback timer.
    private void FinishExit()
    {
        if (!_exiting) return;
        _exitDispatch.Cancel();
        _exiting = false;
        _exitWired = false;
        StateHasChanged();
    }

    // Inert during the exit phase (Context.IsOpen == false, panel only kept
    // mounted for the animation): a stray backdrop click must not re-enter dismiss.
    private Task HandleBackdropClick() => !Context.IsOpen || PreventClose ? Task.CompletedTask : Dismiss("outside");

    private Task HandleSwipe() => Dismiss("swipe");

    // Invoked from JS when a drag settles on a new snap. Mirror it into the
    // two-way ActiveSnapPoint without re-pushing to JS (it's already there).
    private async Task HandleSnapChange(int index)
    {
        _appliedSnap = index;
        if (index != ActiveSnapPoint)
        {
            await ActiveSnapPointChanged.InvokeAsync(index);
        }
    }

    // Registers the appropriate gesture for the current state and records which
    // one (so cleanup/updates target it even if SnapPoints/Side change later).
    private async Task RegisterGestureAsync()
    {
        if (UsesSnapPoints)
        {
            _appliedSnap = InitialSnapIndex;
            // dismissible: a PreventClose drawer still snaps between points but
            // never closes (the gesture settles at the lowest snap instead).
            await Interop.RegisterDrawerSnap(_contentId, SwipeDirection,
                () => Context.TryDismiss("swipe"), HandleSnapChange,
                SnapPoints!, _appliedSnap, !PreventClose,
                GestureOpts.Value.SwipeDismissThresholdPx, GestureOpts.Value.SwipeDismissFirePx, GestureOpts.Value.SwipeDismissVelocity);
            _registeredWithSnap = true;
            _registeredDirection = SwipeDirection;
            _registeredSnapPoints = SnapPoints!.ToArray();
            _gestureRegistered = true;
            if (_appliedSnap != ActiveSnapPoint) await ActiveSnapPointChanged.InvokeAsync(_appliedSnap);
        }
        else if (!PreventClose)
        {
            await Interop.RegisterDrawerSwipe(_contentId, SwipeDirection, HandleSwipe,
                GestureOpts.Value.SwipeDismissThresholdPx, GestureOpts.Value.SwipeDismissFirePx, GestureOpts.Value.SwipeDismissVelocity);
            _registeredWithSnap = false;
            _registeredDirection = SwipeDirection;
            _registeredSnapPoints = null;
            _gestureRegistered = true;
        }
    }

    private async Task UnregisterGestureAsync()
    {
        if (!_gestureRegistered) return;
        if (_registeredWithSnap) await Interop.UnregisterDrawerSnap(_contentId);
        else await Interop.UnregisterDrawerSwipe(_contentId);
        _gestureRegistered = false;
    }

    // True when the SnapPoints fractions baked into the live JS gesture still
    // match the current parameter (sequence-equal). In non-snap mode both sides
    // are null → match, so only a genuine snap-geometry edit (#77) returns false.
    private bool SnapPointsMatchRegistered()
    {
        var current = UsesSnapPoints ? SnapPoints : null;
        if (_registeredSnapPoints is null) return current is null;
        if (current is null) return false;
        return _registeredSnapPoints.SequenceEqual(current);
    }

    protected override async Task OnParametersSetAsync()
    {
        // Passthrough mode — the host DrawerContent owns the shell, exit animation
        // and gesture; this nested instance is a no-op for lifecycle effects.
        if (Shell is not null) return;

        // The exit animation is driven ENTIRELY here, from the open->closed render
        // transition, decoupled from the open-interop completion (the old `_wasOpen`
        // gate). On Blazor Server the open interop is a chain of round-trips; keying
        // the slide/fade-out off `_shownOpen` (flipped true the instant we first
        // render open) makes it play whenever the dismiss lands, and scheduling the
        // unmount here means the panel is never stranded mounted. Snap mode + an
        // opted-out exit (PlayExitAnimation=false) keep ExitDurationMs == 0 →
        // immediate unmount. (B11.)
        if (Context.IsOpen)
        {
            if (_exiting)
            {
                _exitDispatch.Cancel();
                _exiting = false;
                _exitWired = false;
            }
            _shownOpen = true;
        }
        else if (_shownOpen)
        {
            _shownOpen = false;
            if (ExitDurationMs > 0)
            {
                _exiting = true;
                _exitWired = false;
                _exitDispatch.Schedule(ExitDurationMs, () => InvokeAsync(FinishExit));
            }
        }

        // Below is gesture reconciliation, which only applies while the drawer is
        // actually open; skip it during the exit phase (Context.IsOpen == false,
        // panel only kept mounted for the animation — Cleanup already unwired the
        // gesture in the close branch of OnAfterRenderAsync).
        if (!_interopReady || !Context.IsOpen) return;

        // SnapPoints/Side changed while open → the gesture mode flipped (e.g.
        // empty→populated SnapPoints); re-register so the right JS is attached.
        //
        // A same-mode change can also strand the gesture: (#76) a Side flip — or
        // an app/scoped RTL flip — leaves a non-snap gesture wired to the OLD
        // edge (UsesSnapPoints is unchanged for Left↔Right, so the mode gate above
        // never fires); (#77) editing the SnapPoints fraction values (same count,
        // still non-empty) keeps _registeredWithSnap == UsesSnapPoints, so the JS
        // would keep the stale resting geometry. Re-register whenever the live
        // gesture's recorded direction or snap-point array diverges from what the
        // current parameters describe.
        if (_registeredWithSnap != UsesSnapPoints
            || (_gestureRegistered
                && (_registeredDirection != SwipeDirection
                    || !SnapPointsMatchRegistered())))
        {
            await UnregisterGestureAsync();
            await RegisterGestureAsync();
            return;
        }

        // Consumer moved the drawer programmatically (set ActiveSnapPoint to a
        // new in-range index that didn't originate from a gesture) → push to JS.
        if (_registeredWithSnap && SnapPoints is not null
            && ActiveSnapPoint >= 0 && ActiveSnapPoint < SnapPoints.Count
            && ActiveSnapPoint != _appliedSnap)
        {
            _appliedSnap = ActiveSnapPoint;
            await Interop.SetDrawerSnap(_contentId, ActiveSnapPoint);
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Escape" && Context.IsOpen && !PreventClose) await Dismiss("escape");
    }

    private Task Dismiss(string reason) => Context.TryDismiss(reason);

    private async Task Cleanup()
    {
        try
        {
            await UnregisterGestureAsync();
            await Interop.RemoveFocusTrap(_contentId);
            await Interop.UnlockScroll();
        }
        catch (JSDisconnectedException) { }
    }

    public async ValueTask DisposeAsync()
    {
        _exitDispatch.Dispose();
        _selfRef?.Dispose();
        if (_interopReady) await Cleanup();
    }

    public enum DrawerAnimation { Slide, Fade, None }
}

